{
  "domain_analysis": {
    "business_context": "Order cancellation in a logistics/courier context. Users request to cancel an order that has been placed but may be at any stage of fulfillment — from newly created to already in transit. The business must define cancellation eligibility based on fulfillment state, handle financial reversals, and manage downstream operational impacts (e.g., recalling a courier already en route).",
    "bounded_context": "Order Management / Fulfillment",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A request by a user for pickup and delivery of a package between an origin and a destination." },
      { "term": "Order Status", "definition": "The current lifecycle state of an order (e.g., Placed, Confirmed, Assigned, Picked Up, In Transit, Delivered, Cancelled)." },
      { "term": "Cancellation", "definition": "A user-initiated request to terminate an order before final delivery, subject to eligibility rules based on current order status." },
      { "term": "Cancellation Window", "definition": "The set of order statuses during which cancellation is permitted without penalty or with a defined penalty schedule." },
      { "term": "Cancellation Fee", "definition": "A charge applied to the user when cancelling an order that has already progressed past the free-cancellation window." },
      { "term": "Refund", "definition": "The return of payment to the user upon successful cancellation, minus any applicable cancellation fee." },
      { "term": "Courier", "definition": "The assigned driver/rider responsible for physically transporting the package." },
      { "term": "Recall", "definition": "An operational instruction sent to an assigned courier to abort the current pickup or delivery." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order may only be cancelled while it is in a cancellable status. Cancellable statuses are: Placed, Confirmed, Assigned. Once an order reaches Picked Up, In Transit, or Delivered, it is no longer cancellable by the user.",
      "invariant": false,
      "invariant_justification": "The set of cancellable statuses is a business policy decision that leadership could adjust (e.g., allowing cancellation during In Transit with a higher fee). It is not a data-integrity constraint.",
      "testable_assertion": "Given an order with status in {Placed, Confirmed, Assigned}, a cancellation request succeeds. Given an order with status in {Picked Up, In Transit, Delivered, Cancelled}, a cancellation request is rejected."
    },
    {
      "id": "BR-2",
      "rule": "A cancelled order's status must transition to Cancelled and this transition is terminal — a Cancelled order cannot move to any other status.",
      "invariant": true,
      "invariant_justification": "Allowing a Cancelled order to transition back to an active status would corrupt fulfillment state, financial records, and courier assignments. This is a state-integrity constraint.",
      "testable_assertion": "Once an order's status is Cancelled, any attempt to transition it to another status must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Only the user who placed the order (the order owner) may cancel it.",
      "invariant": true,
      "invariant_justification": "Allowing arbitrary users to cancel another user's order is an authorization integrity violation. Admin/support overrides are a separate bounded context with separate audit rules.",
      "testable_assertion": "A cancellation request where requesting_user_id != order.owner_id must be rejected with an authorization error."
    },
    {
      "id": "BR-4",
      "rule": "When an order in status Assigned is cancelled, the system must notify the assigned courier that the assignment is revoked.",
      "invariant": true,
      "invariant_justification": "Failing to notify the courier leaves them performing work on a cancelled order, which corrupts operational state and wastes courier capacity.",
      "testable_assertion": "When an Assigned order is cancelled, a CourierAssignmentRevoked event (or equivalent notification) must be emitted containing the courier ID and order ID."
    },
    {
      "id": "BR-5",
      "rule": "A cancellation fee schedule applies based on order status at time of cancellation: Placed = no fee, Confirmed = no fee, Assigned = cancellation fee applies.",
      "invariant": false,
      "invariant_justification": "Fee amounts and which statuses incur fees are business policy, adjustable by product/finance teams.",
      "testable_assertion": "Cancelling an order in Placed or Confirmed status results in a full refund. Cancelling an order in Assigned status results in a refund minus the cancellation fee."
    },
    {
      "id": "BR-6",
      "rule": "A refund must be issued upon successful cancellation. The refund amount equals the original payment minus any applicable cancellation fee.",
      "invariant": true,
      "invariant_justification": "Cancelling an order without issuing a refund means the business has taken payment for a service it will not render. This is a financial integrity constraint.",
      "testable_assertion": "After a successful cancellation, a Refund record must exist linked to the order with amount = original_payment - cancellation_fee."
    },
    {
      "id": "BR-7",
      "rule": "An order that is already cancelled cannot be cancelled again. The operation must be idempotent — a second cancellation request for an already-cancelled order must return success (not an error) but perform no state change.",
      "invariant": true,
      "invariant_justification": "Double-processing a cancellation could issue duplicate refunds, corrupting financial state.",
      "testable_assertion": "A cancellation request for an already-cancelled order returns a success response and does not create a second refund or emit duplicate events."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An order exists with status Placed, owned by the requesting user",
      "when": "The user submits a cancellation request for that order",
      "then": "The order status transitions to Cancelled, a full refund is issued, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-2",
      "given": "An order exists with status Confirmed, owned by the requesting user",
      "when": "The user submits a cancellation request for that order",
      "then": "The order status transitions to Cancelled, a full refund is issued, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-3",
      "given": "An order exists with status Assigned (courier assigned), owned by the requesting user",
      "when": "The user submits a cancellation request for that order",
      "then": "The order status transitions to Cancelled, the courier is notified of revocation, a refund minus the cancellation fee is issued, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-4",
      "given": "An order exists with status Picked Up",
      "when": "The user submits a cancellation request for that order",
      "then": "The request is rejected with a clear error message indicating the order is no longer cancellable"
    },
    {
      "id": "AC-5",
      "given": "An order exists with status In Transit",
      "when": "The user submits a cancellation request for that order",
      "then": "The request is rejected with a clear error message indicating the order is no longer cancellable"
    },
    {
      "id": "AC-6",
      "given": "An order exists with status Delivered",
      "when": "The user submits a cancellation request for that order",
      "then": "The request is rejected with a clear error message indicating the order is no longer cancellable"
    },
    {
      "id": "AC-7",
      "given": "An order exists with status Cancelled (already cancelled)",
      "when": "The user submits a cancellation request for that order",
      "then": "The request returns success idempotently — no duplicate refund is issued, no duplicate events are emitted"
    },
    {
      "id": "AC-8",
      "given": "An order exists owned by User A",
      "when": "User B (not the owner) submits a cancellation request for that order",
      "then": "The request is rejected with an authorization error, the order status is unchanged"
    },
    {
      "id": "AC-9",
      "given": "A cancellation request references a non-existent order ID",
      "when": "The user submits that cancellation request",
      "then": "The request is rejected with a not-found error"
    },
    {
      "id": "AC-10",
      "given": "An order in Assigned status, and the payment refund service is temporarily unavailable",
      "when": "The user submits a cancellation request",
      "then": "The order status does NOT transition to Cancelled. The cancellation fails atomically — no partial state (cancelled without refund) is persisted. The user receives an error indicating the cancellation could not be completed."
    },
    {
      "id": "AC-11",
      "given": "Two concurrent cancellation requests arrive for the same order in Placed status",
      "when": "Both requests are processed",
      "then": "Exactly one cancellation is processed, exactly one refund is issued, and the second request is handled idempotently"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Race condition: Order status changes from Assigned to Picked Up between the time the user clicks cancel and the backend processes the request",
      "expected_behavior": "The cancellation must be evaluated against the order's status at the moment of state transition (optimistic locking or equivalent). If the order is no longer in a cancellable status, the request is rejected — the user sees a clear message that the order has already been picked up."
    },
    {
      "scenario": "Courier is mid-route to pickup when cancellation of an Assigned order is processed",
      "expected_behavior": "The courier must be notified immediately via the recall mechanism. Any courier compensation for partial work is handled by the cancellation fee, not by leaving the order in an ambiguous state."
    },
    {
      "scenario": "Cancellation request arrives after payment was authorized but before it was captured",
      "expected_behavior": "The payment authorization must be voided rather than captured-then-refunded, to avoid unnecessary transaction costs and float."
    },
    {
      "scenario": "User cancels an order that has a promotional discount or coupon applied",
      "expected_behavior": "The refund is based on the actual amount charged, not the pre-discount amount. The coupon/promo usage should be rolled back so the user can reuse it, subject to promo terms."
    },
    {
      "scenario": "Repeated rapid cancellation requests (potential abuse or bot behavior)",
      "expected_behavior": "Idempotency ensures no double-refund. Rate limiting may apply at the API layer, but the domain layer guarantees correctness regardless of request volume."
    },
    {
      "scenario": "Order is in Assigned status but the courier has not acknowledged the assignment yet",
      "expected_behavior": "The order is still cancellable. The courier notification is best-effort — if the courier never acknowledged, the revocation may be a no-op on their end, which is acceptable."
    },
    {
      "scenario": "Network timeout during cancellation — user is unsure if it succeeded",
      "expected_behavior": "The user can safely retry. Idempotency (BR-7) ensures the second request produces no harmful side effects. The UI should allow the user to check order status."
    },
    {
      "scenario": "Cancellation of an order that is part of a batch/multi-stop delivery",
      "expected_behavior": "Only the specific order is cancelled; the remaining orders in the batch continue. The courier is notified of the removed stop. Route recalculation is triggered if applicable."
    }
  ],

  "business_impact": {
    "financial": "Direct revenue impact: cancellation fees partially offset lost delivery revenue but do not fully recover it. Refund processing incurs payment gateway transaction costs. Promo/coupon rollback affects marketing budget forecasting. Without proper idempotency, double-refund bugs create direct financial loss.",
    "operational": "Courier dispatch efficiency is affected — cancelled-after-assignment orders waste courier time and fuel. Recall notifications must be real-time to minimize wasted capacity. High cancellation rates signal upstream UX or pricing issues that need monitoring.",
    "user": "Cancellation is a trust-building feature — users are more willing to place orders when they know they can cancel. However, unclear cancellation policies or surprise fees damage trust. The error message when cancellation is rejected must clearly explain WHY and WHAT alternatives exist (e.g., contact support).",
    "risk": "Primary risks: (1) Double-refund bugs from non-idempotent implementation — direct financial loss. (2) Partial state corruption where order is cancelled but refund fails — user has no order AND no money. (3) Courier not notified of cancellation — wasted operational capacity and poor courier experience. (4) Race conditions between status transitions and cancellation — leads to inconsistent state.",
    "stakeholders_affected": [
      { "group": "Customers (Order Owners)", "impact": "Gain ability to cancel orders. Positive trust signal. Must receive clear communication about fees and eligibility windows." },
      { "group": "Couriers", "impact": "Directly affected when assigned orders are cancelled. Must be notified promptly. Cancellation fee policy must account for their partial work compensation." },
      { "group": "Finance/Accounting", "impact": "Must reconcile refunds, cancellation fees, and voided authorizations. Need audit trail of all cancellation events." },
      { "group": "Customer Support", "impact": "Will handle edge cases where users want to cancel non-cancellable orders. Need clear escalation paths and override capabilities in their own tooling." },
      { "group": "Product/Analytics", "impact": "Cancellation rate is a key business health metric. Need events emitted with reason codes to analyze cancellation patterns." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec is a single sentence with no detail on cancellation fee amounts, which statuses are cancellable, refund policy, multi-order scenarios, or admin override rules. All business rules above are inferred from standard logistics domain knowledge, not from an actual product specification. Key policy decisions (fee schedule, cancellable statuses, promo rollback rules) are assumptions that MUST be validated with the PM before implementation.",
    "high_confidence_areas": [
      "Terminal state invariant — Cancelled must be a final state",
      "Authorization — only order owner can cancel",
      "Idempotency — double cancellation must not double refund",
      "Courier notification — assigned courier must be informed"
    ],
    "low_confidence_areas": [
      "Exact cancellation fee amounts and schedule",
      "Whether Assigned status should be cancellable or only Placed/Confirmed",
      "Promo/coupon rollback policy",
      "Whether cancellation should be synchronous (atomic with refund) or eventually consistent",
      "Admin/support override cancellation rules",
      "Batch/multi-stop order cancellation behavior"
    ],
    "assumptions": [
      "Order lifecycle includes statuses: Placed, Confirmed, Assigned, Picked Up, In Transit, Delivered, Cancelled",
      "Payment is collected at order placement, not on delivery",
      "Cancellation fees exist for orders that have progressed past Confirmed",
      "Courier notification infrastructure already exists",
      "Refunds go back to original payment method"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define WHICH order statuses are cancellable. The entire cancellation policy hinges on this — whether users can cancel after courier assignment or only before confirmation fundamentally changes operational impact and fee structure.",
      "affected_stakeholders": ["Customers", "Couriers", "Finance"],
      "options": [
        "A: Only Placed and Confirmed are cancellable (conservative — protects courier operations)",
        "B: Placed, Confirmed, and Assigned are cancellable with a fee for Assigned (balanced)",
        "C: All statuses up to and including In Transit are cancellable with escalating fees (aggressive — maximizes user flexibility)"
      ],
      "recommendation": "Option B. Standard industry practice in courier platforms. Protects couriers while giving users reasonable flexibility."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not define cancellation fee amounts or whether fees exist at all. This is a critical financial policy decision.",
      "affected_stakeholders": ["Customers", "Finance", "Product"],
      "options": [
        "A: No cancellation fees ever (simple, user-friendly, but exploitable)",
        "B: Tiered fees based on fulfillment progress (industry standard)",
        "C: Flat cancellation fee regardless of status (simple but potentially unfair)"
      ],
      "recommendation": "Option B. Need PM and Finance to define exact amounts."
    },
    {
      "type": "missing_context",
      "description": "No specification on whether the cancellation + refund must be atomic (synchronous) or can be eventually consistent. This is a critical architectural decision with direct business impact — eventual consistency risks users seeing a cancelled order with no refund.",
      "affected_stakeholders": ["Customers", "Engineering", "Customer Support"],
      "options": [
        "A: Atomic — cancel and refund succeed or fail together",
        "B: Eventually consistent — cancel immediately, refund async with retry"
      ],
      "recommendation": "Option A for correctness. If performance requires Option B, the UI must clearly communicate 'refund is being processed' and support must have visibility into pending refunds."
    },
    {
      "type": "missing_context",
      "description": "No mention of admin/support override capabilities. In practice, support agents will need to cancel orders outside the normal cancellation window (e.g., customer emergency, merchant error). This is a separate but related capability that must be planned for.",
      "affected_stakeholders": ["Customer Support", "Customers"],
      "options": [
        "A: Build admin override in the same feature",
        "B: Scope this feature to user-initiated only, plan admin override as a follow-up"
      ],
      "recommendation": "Option B. Ship user cancellation first, but design the domain model to accommodate admin overrides later (e.g., cancellation reason codes, actor type on the event)."
    }
  ],

  "rejection_reasons": []
}

